package com.corporativoalpha.bookingservice.models;import jakarta.persistence.*;import jakarta.validation.constraints.Min;import jakarta.validation.constraints.NotNull;import java.time.LocalDate;import java.time.LocalTime;@Entity@Table(name = "bookings")public class Booking {@Id@GeneratedValue(strategy = GenerationType.IDENTITY)private Long id;@ManyToOne@JoinColumn(name = "user_id", nullable = false)private User user;@ManyToOne@JoinColumn(name = "space_id", nullable = false)private Space space;@NotNull@Column(name = "booking_date", nullable = false)private LocalDate bookingDate;@NotNull@Column(name = "start_time", nullable = false)private LocalTime startTime;@NotNull@Column(name = "end_time", nullable = false)private LocalTime endTime;@NotNull@Min(1)@Column(nullable = false)private Integer attendees;public Long getId(){return id;}public void setId(Long id){this.id=id;}public User getUser(){return user;}public void setUser(User user){this.user=user;}public Space getSpace(){return space;}public void setSpace(Space space){this.space=space;}public LocalDate getBookingDate(){return bookingDate;}public void setBookingDate(LocalDate bookingDate){this.bookingDate=bookingDate;}public LocalTime getStartTime(){return startTime;}public void setStartTime(LocalTime startTime){this.startTime=startTime;}public LocalTime getEndTime(){return endTime;}public void setEndTime(LocalTime endTime){this.endTime=endTime;}public Integer getAttendees(){return attendees;}public void setAttendees(Integer attendees){this.attendees=attendees;}}
